body:
Hello, 

I'm not sure if it's a bug or just an unimplemented feature: I want to modify with VPI the value of a multidimensional packed array, but the function "vpi_handle_by_name()" return a null value. If I replace the multidimensional array by a simple array, it's ok. I have found information about unpacked arrays but not about packed arrays.

counter.sv:
```
module counter  (
                output logic [1:0][4:0] count /*verilator public_flat_rw*/,
                input        clk  ,
                input        rst   
                );

	timeunit 1ns;
	timeprecision 100ps;

	always_ff @(posedge clk, posedge rst)
	begin
		if (rst == 1)
			count[0] <= 5'b0;
		else
			count[0] <= count[0] + 1;
		count[1] <= 5'b0;
	end
endmodule
```
sim_main.cpp:
```
#include "Vcounter.h"
#include "verilated_vcd_c.h"
#include "verilated_vpi.h"

#define VM_TRACE 1

vluint64_t main_time = 0;
double sc_time_stamp(){
	return main_time;
}

// function that adds 5 to the count variable of the counter module:
void modify_count(){
	vpiHandle count_handler = vpi_handle_by_name((PLI_BYTE8*)"TOP.counter.count", NULL);
	if(!count_handler) { vl_fatal(__FILE__, __LINE__, "sim_main", "No handler found"); }
	s_vpi_value val;
	val.format = vpiIntVal;
	vpi_get_value(count_handler, &val);
	val.value.integer += 5;
	vpi_put_value(count_handler, &val, NULL, vpiForceFlag);
}

int main(int argc, char** argv, char** env){
	Verilated::commandArgs(argc, argv);
	Vcounter *top = new Vcounter;
	#if VM_TRACE
		VerilatedVcdC *m_trace = new VerilatedVcdC;
		Verilated::traceEverOn(true);
		top->trace(m_trace, 99);
		m_trace->open("waveforms.vcd");
	#endif

	// reset the counter and then try to modify the value
	top->clk = 0;
	top->rst = 1;
	top->eval();
	#if VM_TRACE 
		m_trace->dump(0);
	#endif

	top->clk = 1;
	top->eval();
	#if VM_TRACE 
		m_trace->dump(1);
	#endif

	top->rst = 0;
	modify_count(); // modify the value
	
	for(int i=0; i<10; i++){
		top->clk = !top->clk;
		top->eval();
		#if VM_TRACE 
			m_trace->dump(2+i);
		#endif
	}

	top->final();
	#if VM_TRACE
		m_trace->close();
		m_trace = NULL;
	#endif
	delete top;
	exit(EXIT_SUCCESS);
}
```
I compile with: "verilator -Wall --cc --vpi --trace counter.sv --exe --build sim_main.cpp", and when I execute I obtain: "%Error: ../sim_main.cpp:14: No handler found".
(tested with verilator version 4.110)
It probably lacks some code to correctly modify the array, but it seems that the problem is about the call to vpi_handle_by_name().

Thank you for your help.
